#!/usr/bin/env dotnet
// Find the earliest Friday the 13th in the proleptic Gregorian calendar
// and count all Friday the 13ths in a full 400-year cycle.

// Earliest Friday the 13th starting from 0001-01-01
DateOnly date = new DateOnly(1, 1, 13); // start checking the 13th of each month
DateOnly earliest = default;

for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            if (earliest == default)
            {
                earliest = d;
            }
            break; // found first one, but keep counting below
        }
    }
    if (earliest != default) break;
}

Console.WriteLine($"Earliest Friday the 13th: {earliest:yyyy-MM-dd}");

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            count++;
        }
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: which months have the most Friday the 13ths in a 400-year cycle?
var byMonth = new int[12];
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            byMonth[month - 1]++;
    }
}

Console.WriteLine("\nFriday the 13ths by month (400-year cycle):");
for (int m = 0; m < 12; m++)
{
    Console.WriteLine($"  {new DateOnly(2000, m + 1, 1):MMMM,-12} {byMonth[m]}");
}
EOF
